def run_length_encode(data):
    if not data:
        return ""

    encoded_parts = []
    count = 0
    current_char = ''

    for char in data:
        if not current_char:
            current_char = char
            count = 1
        elif char == current_char:
            count += 1
        else:
            encoded_parts.append(str(count))
            encoded_parts.append(current_char)
            current_char = char
            count = 1

    if current_char:
        encoded_parts.append(str(count))
        encoded_parts.append(current_char)

    return "".join(encoded_parts)
